const input = $input.first().json;

var catalogText = (input.catalog || []).map(function(p) {
  if (!p || !p.name) return null;
  var line = '- ' + p.name;
  if (p.price) line += ' | $' + Number(p.price).toLocaleString('es-CO');
  if (p.category) line += ' | ' + p.category;
  if (p.available === false) line += ' [NO DISPONIBLE]';
  if (p.description) line += ': ' + p.description;
  return line;
}).filter(Boolean).join('\n') || 'No hay catálogo disponible.';

var faqText = (input.faq || []).map(function(f) {
  if (!f || !f.question) return null;
  return 'P: ' + f.question + '\nR: ' + f.answer;
}).filter(Boolean).join('\n\n') || 'No hay preguntas frecuentes.';

var payText = (input.paymentMethods || []).join(', ') || 'No especificado';
var locationText = input.location || 'No especificada';

var systemMessage = (input.aiInstructions || 'Eres un asistente de atención al cliente. Sé amable y profesional.') +
  '\n\nNombre del cliente: ' + (input.pushName || 'Cliente') +
  '\n\nEl sistema no pudo clasificar con certeza la intención del cliente.' +
  '\nTu trabajo es dar una respuesta útil y amable, e intentar clarificar qué necesita.' +
  '\n\nCATÁLOGO DEL NEGOCIO:\n' + catalogText +
  '\n\nPREGUNTAS FRECUENTES:\n' + faqText +
  '\n\nMétodos de pago: ' + payText +
  '\nUbicación: ' + locationText +
  '\n\nREGLAS:' +
  '\n1. Responde de forma amable y profesional' +
  '\n2. Intenta responder con la información disponible del negocio' +
  '\n3. Si no puedes determinar qué necesita, ofrece las opciones principales' +
  '\n4. Sugiérele que reformule si la pregunta es ambigua' +
  '\n5. Respuestas cortas, máximo 3-4 oraciones' +
  '\n6. NO inventes información' +
  '\n7. Responde en español';

return [{
  json: {
    phone: input.phone,
    tenant_id: input.tenantId,
    pushName: input.pushName,
    message: input.message,
    instance: input.instanceName,
    business_name: input.businessName,
    intent_original: input.intent || 'fallback',
    confidence_original: input.confidence || 0,
    ai_response_clasificador: input.ai_response || '',
    systemMessage: systemMessage
  }
}];

const input = $('Preparar Contexto Fallback').first().json;
const aiOutput = $input.first().json;

// Prioridad: usar respuesta de Clasificar Intencion si existe (evita doble llamada AI)
// Si el clasificador ya genero una respuesta valida, usarla directamente sin nueva llamada a OpenAI
const aiClasificadorResp = (input.ai_response_clasificador || '').trim();
const agenteFallbackResp = (aiOutput.output || aiOutput.text || '').trim();
const defaultMsg = 'Lo siento, no logre entender tu mensaje. Puedo ayudarte con informacion del negocio, ventas, soporte o agendar una cita.';

// Preferir respuesta del clasificador (ya tiene el contexto completo del negocio)
const response = (aiClasificadorResp.length > 15 ? aiClasificadorResp : null)
  || (agenteFallbackResp.length > 5 ? agenteFallbackResp : null)
  || defaultMsg;

return [{
  json: {
    response: response,
    phone: input.phone,
    tenant_id: input.tenant_id,
    intent_handled: 'fallback',
    action_taken: 'respuesta_general',
    confidence: input.confidence_original,
    metadata: {
      pushName: input.pushName,
      original_message: input.message,
      intent_original: input.intent_original,
      source: aiClasificadorResp.length > 15 ? 'clasificador' : 'agente_fallback'
    }
  }
}];

